/* ============================== helpers ============================== */

const uid = () => Math.random().toString(36).slice(2, 10) + Date.now().toString(36).slice(-4);

function toISO(d) {
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, "0");
  const day = String(d.getDate()).padStart(2, "0");
  return `${y}-${m}-${day}`;
}
const todayStr = () => toISO(new Date());
const nowTime = () => {
  const d = new Date();
  return `${String(d.getHours()).padStart(2, "0")}:${String(d.getMinutes()).padStart(2, "0")}`;
};
const peso = (n) =>
  `\u20B1${(Number(n) || 0).toLocaleString("en-PH", { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
const fmtDate = (s) => {
  if (!s) return "\u2014";
  const d = new Date(s + "T00:00:00");
  return d.toLocaleDateString("en-PH", { month: "short", day: "numeric", year: "numeric" });
};
const fmtTime = (t) => {
  if (!t) return "\u2014";
  const [h, m] = t.split(":").map(Number);
  const hh = ((h + 11) % 12) + 1;
  const ampm = h < 12 ? "AM" : "PM";
  return `${hh}:${String(m).padStart(2, "0")} ${ampm}`;
};
function hoursBetween(timeIn, timeOut) {
  if (!timeIn || !timeOut) return 0;
  const [h1, m1] = timeIn.split(":").map(Number);
  const [h2, m2] = timeOut.split(":").map(Number);
  let mins = h2 * 60 + m2 - (h1 * 60 + m1);
  if (mins < 0) mins += 24 * 60;
  return Math.round((mins / 60) * 100) / 100;
}
function addDays(dateStr, n) {
  const d = new Date(dateStr + "T00:00:00");
  d.setDate(d.getDate() + n);
  return toISO(d);
}
function startOfMonth(dateStr) {
  const d = new Date(dateStr + "T00:00:00");
  return toISO(new Date(d.getFullYear(), d.getMonth(), 1));
}
function endOfMonth(dateStr) {
  const d = new Date(dateStr + "T00:00:00");
  return toISO(new Date(d.getFullYear(), d.getMonth() + 1, 0));
}
function mondayOf(dateStr) {
  const d = new Date(dateStr + "T00:00:00");
  const day = d.getDay();
  const diff = day === 0 ? -6 : 1 - day;
  d.setDate(d.getDate() + diff);
  return toISO(d);
}
function shiftMonthStart(dateStr, n) {
  const d = new Date(dateStr + "T00:00:00");
  d.setDate(1);
  d.setMonth(d.getMonth() + n);
  return toISO(d);
}
function fmtShortDate(dateStr) {
  const d = new Date(dateStr + "T00:00:00");
  return d.toLocaleDateString("en-PH", { month: "short", day: "numeric" });
}
function fmtMonthLabel(dateStr) {
  const d = new Date(dateStr + "T00:00:00");
  return d.toLocaleDateString("en-PH", { month: "short", year: "2-digit" });
}

/** Builds trend buckets (Cash In / Cash Out / Net) for the dashboard analytics chart. */
function buildAnalyticsBuckets(transactions, period) {
  const today = todayStr();
  const defs = [];
  if (period === "daily") {
    for (let i = 13; i >= 0; i--) {
      const d = addDays(today, -i);
      defs.push({ label: fmtShortDate(d), from: d, to: d });
    }
  } else if (period === "weekly") {
    const thisMonday = mondayOf(today);
    for (let i = 7; i >= 0; i--) {
      const from = addDays(thisMonday, -7 * i);
      const to = addDays(from, 6);
      defs.push({ label: fmtShortDate(from), from, to });
    }
  } else if (period === "monthly") {
    for (let i = 11; i >= 0; i--) {
      const from = shiftMonthStart(today, -i);
      defs.push({ label: fmtMonthLabel(from), from, to: endOfMonth(from) });
    }
  } else {
    const y = Number(today.slice(0, 4));
    for (let i = 4; i >= 0; i--) {
      const yr = y - i;
      defs.push({ label: String(yr), from: `${yr}-01-01`, to: `${yr}-12-31` });
    }
  }
  return defs.map((b) => {
    const txs = transactions.filter((t) => t.date >= b.from && t.date <= b.to);
    const cashIn = round2(txs.filter((t) => t.type === "in").reduce((a, c) => a + Number(c.amount || 0), 0));
    const cashOut = round2(txs.filter((t) => t.type === "out").reduce((a, c) => a + Number(c.amount || 0), 0));
    return { label: b.label, cashIn, cashOut, net: round2(cashIn - cashOut) };
  });
}

/** Category totals for transactions within a date range, sorted descending. */
function categoryTotals(transactions, type, from, to) {
  const map = {};
  transactions
    .filter((t) => t.type === type && t.date >= from && t.date <= to)
    .forEach((t) => { map[t.category] = (map[t.category] || 0) + Number(t.amount || 0); });
  return Object.entries(map)
    .map(([category, total]) => ({ category, total: round2(total) }))
    .sort((a, b) => b.total - a.total);
}
function downloadCSV(filename, rows) {
  const csv = rows
    .map((r) =>
      r
        .map((cell) => {
          const s = String(cell ?? "");
          return /[",\n]/.test(s) ? `"${s.replace(/"/g, '""')}"` : s;
        })
        .join(",")
    )
    .join("\n");
  const blob = new Blob([csv], { type: "text/csv;charset=utf-8;" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
  URL.revokeObjectURL(url);
}

