/* ============================== Dashboard ============================== */

function Dashboard({ transactions, medications, supplies, employees, attendance, setActive }) {
  const today = todayStr();
  const monthStart = startOfMonth(today);
  const [period, setPeriod] = useState("monthly");

  const todayTx = transactions.filter((t) => t.date === today);
  const monthTx = transactions.filter((t) => t.date >= monthStart && t.date <= today);
  const sum = (arr, type) => arr.filter((t) => t.type === type).reduce((a, b) => a + Number(b.amount || 0), 0);

  const todayIn = sum(todayTx, "in");
  const todayOut = sum(todayTx, "out");
  const monthIn = sum(monthTx, "in");
  const monthOut = sum(monthTx, "out");

  const lowMeds = medications.items.filter((i) => Number(i.quantity) <= Number(i.reorderLevel));
  const lowSup = supplies.items.filter((i) => Number(i.quantity) <= Number(i.reorderLevel));
  const lowStock = [...lowMeds.map((i) => ({ ...i, kind: "Medication" })), ...lowSup.map((i) => ({ ...i, kind: "Supply" }))];

  const activeEmployees = employees.filter((e) => e.status === "Active");
  const presentToday = attendance.filter(
    (a) => a.date === today && ["Present", "Late", "Half Day"].includes(a.status)
  ).length;

  const recent = [...transactions]
    .sort((a, b) => (b.date + String(b.createdAt || 0)).localeCompare(a.date + String(a.createdAt || 0)))
    .slice(0, 6);

  const chartData = useMemo(() => buildAnalyticsBuckets(transactions, period), [transactions, period]);
  // Recompute the actual from/to range covered so the category tables match the chart window
  const bucketDefs = useMemo(() => {
    const raw = period === "daily" ? 14 : period === "weekly" ? 8 : period === "monthly" ? 12 : 5;
    if (period === "daily") return { from: addDays(today, -(raw - 1)), to: today };
    if (period === "weekly") return { from: addDays(mondayOf(today), -7 * (raw - 1)), to: addDays(mondayOf(today), 6) };
    if (period === "monthly") return { from: shiftMonthStart(today, -(raw - 1)), to: endOfMonth(today) };
    const y = Number(today.slice(0, 4));
    return { from: `${y - (raw - 1)}-01-01`, to: `${y}-12-31` };
  }, [period, today]);

  const inByCategory = categoryTotals(transactions, "in", bucketDefs.from, bucketDefs.to).slice(0, 6);
  const outByCategory = categoryTotals(transactions, "out", bucketDefs.from, bucketDefs.to).slice(0, 6);

  const periodLabels = { daily: "Daily", weekly: "Weekly", monthly: "Monthly", yearly: "Yearly" };

  return (
    <div className="space-y-6">
      <div className="bg-white rounded-2xl border border-stone-200 shadow-sm p-5 flex items-center gap-4">
        <img src={CLINIC_LOGO_FULL} alt="JSJ Skin Care Medical and Aesthetic Clinic logo" className="h-16 w-16 sm:h-20 sm:w-20 object-contain shrink-0" />
        <div className="min-w-0">
          <div className="font-serif text-xl text-stone-900 truncate">JSJ Skin Care Medical and Aesthetic Clinic</div>
          <div className="text-sm text-stone-500 mt-0.5">Welcome back. Here's how the clinic is doing.</div>
        </div>
      </div>

      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        <StatCard label="Today's Cash In" value={peso(todayIn)} icon={ArrowUpCircle} tone="green" />
        <StatCard label="Today's Cash Out" value={peso(todayOut)} icon={ArrowDownCircle} tone="red" />
        <StatCard label="Net Today" value={peso(todayIn - todayOut)} icon={Wallet} tone="rose" />
        <StatCard label="Present Today" value={`${presentToday} / ${activeEmployees.length}`} icon={Users} tone="gold" />
      </div>

      <div className="bg-white rounded-2xl p-5 border border-stone-200 shadow-sm">
        <div className="flex flex-wrap items-center justify-between gap-3 mb-4">
          <h3 className="font-serif text-base text-stone-900">Cash Flow Analytics</h3>
          <div className="flex gap-1 bg-stone-100 p-1 rounded-lg">
            {["daily", "weekly", "monthly", "yearly"].map((p) => (
              <button
                key={p}
                onClick={() => setPeriod(p)}
                className={`px-3 py-1.5 rounded-md text-xs font-medium transition-colors ${
                  period === p ? "bg-white shadow text-stone-900" : "text-stone-500 hover:text-stone-700"
                }`}
              >
                {periodLabels[p]}
              </button>
            ))}
          </div>
        </div>

        {transactions.length === 0 ? (
          <EmptyState icon={Wallet} text="No transactions yet to chart." />
        ) : (
          <div style={{ width: "100%", height: 260 }}>
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData} margin={{ top: 4, right: 8, left: 0, bottom: 0 }}>
                <CartesianGrid strokeDasharray="3 3" stroke="#e7e5e4" vertical={false} />
                <XAxis dataKey="label" tick={{ fontSize: 11, fill: "#78716c" }} axisLine={{ stroke: "#e7e5e4" }} tickLine={false} />
                <YAxis
                  tick={{ fontSize: 11, fill: "#78716c" }}
                  axisLine={false}
                  tickLine={false}
                  tickFormatter={(v) => (v >= 1000 ? `${Math.round(v / 1000)}k` : v)}
                  width={40}
                />
                <Tooltip formatter={(v) => peso(v)} contentStyle={{ fontSize: 12, borderRadius: 8, borderColor: "#e7e5e4" }} />
                <Legend wrapperStyle={{ fontSize: 12 }} />
                <Bar dataKey="cashIn" name="Cash In" fill="#3F6B4A" radius={[4, 4, 0, 0]} maxBarSize={28} />
                <Bar dataKey="cashOut" name="Cash Out" fill="#B3453A" radius={[4, 4, 0, 0]} maxBarSize={28} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        )}

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mt-5 pt-5 border-t border-stone-100">
          <div>
            <h4 className="text-xs uppercase tracking-wide text-stone-500 mb-2">Cash In by Category</h4>
            {inByCategory.length === 0 ? (
              <p className="text-sm text-stone-400">No income recorded for this range.</p>
            ) : (
              <table className="w-full text-sm">
                <tbody>
                  {inByCategory.map((c) => (
                    <tr key={c.category} className="border-t border-stone-100 first:border-t-0">
                      <td className="py-1.5 text-stone-600">{c.category}</td>
                      <td className="py-1.5 text-right font-medium text-emerald-600">{peso(c.total)}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}
          </div>
          <div>
            <h4 className="text-xs uppercase tracking-wide text-stone-500 mb-2">Cash Out by Category</h4>
            {outByCategory.length === 0 ? (
              <p className="text-sm text-stone-400">No expenses recorded for this range.</p>
            ) : (
              <table className="w-full text-sm">
                <tbody>
                  {outByCategory.map((c) => (
                    <tr key={c.category} className="border-t border-stone-100 first:border-t-0">
                      <td className="py-1.5 text-stone-600">{c.category}</td>
                      <td className="py-1.5 text-right font-medium text-red-600">{peso(c.total)}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
        <div className="bg-white rounded-2xl p-5 border border-stone-200 shadow-sm">
          <h3 className="font-serif text-base text-stone-900 mb-3">This Month</h3>
          <div className="space-y-2 text-sm">
            <div className="flex justify-between"><span className="text-stone-500">Cash In</span><span className="text-emerald-600 font-medium">{peso(monthIn)}</span></div>
            <div className="flex justify-between"><span className="text-stone-500">Cash Out</span><span className="text-red-600 font-medium">{peso(monthOut)}</span></div>
            <div className="flex justify-between pt-2 border-t border-stone-100"><span className="text-stone-800 font-medium">Net</span><span className="font-semibold text-stone-900">{peso(monthIn - monthOut)}</span></div>
          </div>
        </div>

        <div className="bg-white rounded-2xl p-5 border border-stone-200 shadow-sm">
          <div className="flex items-center justify-between mb-3">
            <h3 className="font-serif text-base text-stone-900">Low Stock Alerts</h3>
            {lowStock.length > 0 && <Badge tone="amber">{lowStock.length}</Badge>}
          </div>
          {lowStock.length === 0 ? (
            <p className="text-sm text-stone-400">All stock levels look healthy.</p>
          ) : (
            <ul className="space-y-2">
              {lowStock.slice(0, 5).map((i) => (
                <li key={i.kind + i.id} className="flex items-center justify-between text-sm gap-2">
                  <span className="flex items-center gap-1.5 text-stone-700 min-w-0 truncate">
                    <AlertTriangle size={14} className="text-amber-500 shrink-0" />
                    <span className="truncate">{i.name}</span>
                  </span>
                  <span className="text-red-600 font-medium shrink-0">{i.quantity} {i.unit}</span>
                </li>
              ))}
            </ul>
          )}
          <button
            onClick={() => setActive(lowMeds.length >= lowSup.length ? "medications" : "supplies")}
            className="mt-3 text-xs text-rose-600 font-medium hover:underline"
          >
            View inventory &rarr;
          </button>
        </div>

        <div className="bg-white rounded-2xl p-5 border border-stone-200 shadow-sm">
          <h3 className="font-serif text-base text-stone-900 mb-3">Recent Transactions</h3>
          {recent.length === 0 ? (
            <p className="text-sm text-stone-400">No transactions yet.</p>
          ) : (
            <ul className="space-y-2">
              {recent.map((t) => (
                <li key={t.id} className="flex items-center justify-between text-sm gap-2">
                  <span className="truncate min-w-0 text-stone-600">{t.clientName ? `${t.category} \u2014 ${t.clientName}` : t.category}</span>
                  <span className={`shrink-0 font-medium ${t.type === "in" ? "text-emerald-600" : "text-red-600"}`}>
                    {t.type === "in" ? "+" : "-"}{peso(t.amount)}
                  </span>
                </li>
              ))}
            </ul>
          )}
          <button onClick={() => setActive("sales")} className="mt-3 text-xs text-rose-600 font-medium hover:underline">
            View all sales &rarr;
          </button>
        </div>
      </div>
    </div>
  );
}

/* ============================== Sales ============================== */

function TransactionModal({ initial, onClose, onSave }) {
  const [type, setType] = useState(initial?.type || "in");
  const [category, setCategory] = useState(initial?.category || CASH_IN_CATEGORIES[0]);
  const [amount, setAmount] = useState(initial?.amount ?? "");
  const [date, setDate] = useState(initial?.date || todayStr());
  const [description, setDescription] = useState(initial?.description || "");
  const [clientName, setClientName] = useState(initial?.clientName || "");

  const cats = type === "in" ? CASH_IN_CATEGORIES : CASH_OUT_CATEGORIES;

  useEffect(() => {
    if (!cats.includes(category)) setCategory(cats[0]);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [type]);

  const submit = () => {
    if (!amount || Number(amount) <= 0) return;
    onSave({ type, category, amount: Number(amount), date, description, clientName: type === "in" ? clientName : "" });
  };

  return (
    <Modal
      title={initial ? "Edit Transaction" : "Add Transaction"}
      onClose={onClose}
      footer={<><button onClick={onClose} className={btnGhost}>Cancel</button><button onClick={submit} className={btnPrimary}>Save</button></>}
    >
      <Field label="Type">
        <div className="flex gap-2">
          <button type="button" onClick={() => setType("in")} className={`flex-1 py-2 rounded-lg text-sm font-medium border ${type === "in" ? "bg-emerald-50 border-emerald-300 text-emerald-700" : "border-stone-300 text-stone-500"}`}>Cash In</button>
          <button type="button" onClick={() => setType("out")} className={`flex-1 py-2 rounded-lg text-sm font-medium border ${type === "out" ? "bg-red-50 border-red-300 text-red-700" : "border-stone-300 text-stone-500"}`}>Cash Out</button>
        </div>
      </Field>
      <Field label="Category">
        <select value={category} onChange={(e) => setCategory(e.target.value)} className={inputCls()}>
          {cats.map((c) => <option key={c} value={c}>{c}</option>)}
        </select>
      </Field>
      {type === "in" && (
        <Field label="Client Name (optional)">
          <input value={clientName} onChange={(e) => setClientName(e.target.value)} className={inputCls()} placeholder="e.g. Juan Dela Cruz" />
        </Field>
      )}
      <Field label="Amount (PHP)">
        <input type="number" min="0" step="0.01" value={amount} onChange={(e) => setAmount(e.target.value)} className={inputCls()} placeholder="0.00" />
      </Field>
      <Field label="Date">
        <input type="date" value={date} onChange={(e) => setDate(e.target.value)} className={inputCls()} />
      </Field>
      <Field label="Description (optional)">
        <input value={description} onChange={(e) => setDescription(e.target.value)} className={inputCls()} placeholder="e.g. Facial treatment" />
      </Field>
    </Modal>
  );
}

function SalesSection({ transactions, setTransactions, notify, askConfirm }) {
  const [typeFilter, setTypeFilter] = useState("all");
  const [catFilter, setCatFilter] = useState("all");
  const [from, setFrom] = useState("");
  const [to, setTo] = useState("");
  const [search, setSearch] = useState("");
  const [modalOpen, setModalOpen] = useState(false);
  const [editing, setEditing] = useState(null);

  const filtered = useMemo(() => {
    return transactions
      .filter((t) => {
        if (typeFilter !== "all" && t.type !== typeFilter) return false;
        if (catFilter !== "all" && t.category !== catFilter) return false;
        if (from && t.date < from) return false;
        if (to && t.date > to) return false;
        if (search) {
          const s = search.toLowerCase();
          if (
            !(t.description || "").toLowerCase().includes(s) &&
            !(t.clientName || "").toLowerCase().includes(s) &&
            !t.category.toLowerCase().includes(s)
          ) return false;
        }
        return true;
      })
      .sort((a, b) => (b.date + String(b.createdAt || 0)).localeCompare(a.date + String(a.createdAt || 0)));
  }, [transactions, typeFilter, catFilter, from, to, search]);

  const totalIn = filtered.filter((t) => t.type === "in").reduce((a, b) => a + Number(b.amount || 0), 0);
  const totalOut = filtered.filter((t) => t.type === "out").reduce((a, b) => a + Number(b.amount || 0), 0);
  const allCategories = [...CASH_IN_CATEGORIES, ...CASH_OUT_CATEGORIES];

  const save = (txn) => {
    if (editing) {
      setTransactions((prev) => prev.map((t) => (t.id === editing.id ? { ...t, ...txn } : t)));
      notify("Transaction updated");
    } else {
      setTransactions((prev) => [{ id: uid(), createdAt: Date.now(), ...txn }, ...prev]);
      notify("Transaction recorded");
    }
    setModalOpen(false);
    setEditing(null);
  };

  const remove = (id) => {
    askConfirm("Delete this transaction? This cannot be undone.", () => {
      setTransactions((prev) => prev.filter((t) => t.id !== id));
      notify("Transaction deleted");
    });
  };

  const exportCsv = () => {
    downloadCSV(`sales_${todayStr()}.csv`, [
      ["Date", "Type", "Category", "Client Name", "Description", "Amount"],
      ...filtered.map((t) => [t.date, t.type === "in" ? "Cash In" : "Cash Out", t.category, t.clientName || "", t.description || "", t.amount]),
    ]);
  };

  return (
    <div className="space-y-5">
      <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
        <div className="bg-white rounded-2xl p-4 border border-stone-200"><div className="text-xs text-stone-500 mb-1">Cash In</div><div className="font-serif text-xl text-emerald-600">{peso(totalIn)}</div></div>
        <div className="bg-white rounded-2xl p-4 border border-stone-200"><div className="text-xs text-stone-500 mb-1">Cash Out</div><div className="font-serif text-xl text-red-600">{peso(totalOut)}</div></div>
        <div className="bg-white rounded-2xl p-4 border border-stone-200"><div className="text-xs text-stone-500 mb-1">Net</div><div className="font-serif text-xl text-stone-900">{peso(totalIn - totalOut)}</div></div>
      </div>

      <div className="bg-white rounded-2xl border border-stone-200 shadow-sm">
        <div className="flex flex-wrap items-center gap-2 p-4 border-b border-stone-100">
          <div className="relative flex-1">
            <Search size={15} className="absolute left-2.5 top-2.5 text-stone-400" />
            <input value={search} onChange={(e) => setSearch(e.target.value)} placeholder="Search description, client, or category" className={inputCls() + " pl-8"} />
          </div>
          <select value={typeFilter} onChange={(e) => { setTypeFilter(e.target.value); setCatFilter("all"); }} className={inputCls("w-auto")}>
            <option value="all">All Types</option>
            <option value="in">Cash In</option>
            <option value="out">Cash Out</option>
          </select>
          <select value={catFilter} onChange={(e) => setCatFilter(e.target.value)} className={inputCls("w-auto")}>
            <option value="all">All Categories</option>
            {(typeFilter === "in" ? CASH_IN_CATEGORIES : typeFilter === "out" ? CASH_OUT_CATEGORIES : allCategories).map((c) => (
              <option key={c} value={c}>{c}</option>
            ))}
          </select>
          <input type="date" value={from} onChange={(e) => setFrom(e.target.value)} className={inputCls("w-auto")} />
          <input type="date" value={to} onChange={(e) => setTo(e.target.value)} className={inputCls("w-auto")} />
          <button onClick={exportCsv} className={btnGhost}><Download size={15} />Export</button>
          <button onClick={() => { setEditing(null); setModalOpen(true); }} className={btnPrimary}><Plus size={16} />Add Transaction</button>
        </div>

        <div className="overflow-x-auto">
          {filtered.length === 0 ? (
            <EmptyState icon={Wallet} text="No transactions found." />
          ) : (
            <table className="w-full text-sm">
              <thead>
                <tr className="text-left text-xs text-stone-500 uppercase">
                  <th className="px-4 py-2">Date</th><th className="px-4 py-2">Type</th><th className="px-4 py-2">Category</th><th className="px-4 py-2">Client</th><th className="px-4 py-2">Description</th><th className="px-4 py-2 text-right">Amount</th><th className="px-4 py-2"></th>
                </tr>
              </thead>
              <tbody>
                {filtered.map((t) => (
                  <tr key={t.id} className="border-t border-stone-100 hover:bg-stone-50">
                    <td className="px-4 py-2.5 whitespace-nowrap">{fmtDate(t.date)}</td>
                    <td className="px-4 py-2.5">
                      {t.type === "in" ? (
                        <span className="inline-flex items-center gap-1 text-emerald-600"><ArrowUpCircle size={14} />In</span>
                      ) : (
                        <span className="inline-flex items-center gap-1 text-red-600"><ArrowDownCircle size={14} />Out</span>
                      )}
                    </td>
                    <td className="px-4 py-2.5"><Badge tone="rose">{t.category}</Badge></td>
                    <td className="px-4 py-2.5 text-stone-600 w-28 truncate">{t.clientName || "\u2014"}</td>
                    <td className="px-4 py-2.5 text-stone-600 max-w-xs truncate">{t.description || "\u2014"}</td>
                    <td className={`px-4 py-2.5 text-right font-medium ${t.type === "in" ? "text-emerald-600" : "text-red-600"}`}>
                      {t.type === "in" ? "+" : "-"}{peso(t.amount)}
                    </td>
                    <td className="px-4 py-2.5">
                      <div className="flex items-center gap-1 justify-end">
                        <button className={btnIcon} onClick={() => { setEditing(t); setModalOpen(true); }}><Pencil size={14} /></button>
                        <button className={btnIcon} onClick={() => remove(t.id)}><Trash2 size={14} /></button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </div>

      {modalOpen && (
        <TransactionModal initial={editing} onClose={() => { setModalOpen(false); setEditing(null); }} onSave={save} />
      )}
    </div>
  );
}

/* ============================== Inventory (Medications / Supplies) ============================== */

function ItemFormModal({ title, initial, hideQuantity, unitOptions, onClose, onSave }) {
  const [name, setName] = useState(initial?.name || "");
  const [unit, setUnit] = useState(initial?.unit || (unitOptions?.[0] || "pcs"));
  const [quantity, setQuantity] = useState(initial?.quantity ?? 0);
  const [reorderLevel, setReorderLevel] = useState(initial?.reorderLevel ?? 5);
  const [notes, setNotes] = useState(initial?.notes || "");
  const listId = useRef(`units-${uid()}`).current;

  const submit = () => {
    if (!name.trim()) return;
    const patch = { name: name.trim(), unit, reorderLevel: Number(reorderLevel) || 0, notes };
    if (!hideQuantity) patch.quantity = Number(quantity) || 0;
    onSave(patch);
  };

  return (
    <Modal title={title} onClose={onClose} footer={<><button onClick={onClose} className={btnGhost}>Cancel</button><button onClick={submit} className={btnPrimary}>Save</button></>}>
      <Field label="Name">
        <input value={name} onChange={(e) => setName(e.target.value)} className={inputCls()} placeholder="e.g. Tretinoin Cream" autoFocus />
      </Field>
      <div className="grid grid-cols-2 gap-3">
        <Field label="Unit">
          <input list={listId} value={unit} onChange={(e) => setUnit(e.target.value)} className={inputCls()} />
          <datalist id={listId}>{(unitOptions || []).map((u) => <option key={u} value={u} />)}</datalist>
        </Field>
        {!hideQuantity && (
          <Field label="Initial Quantity">
            <input type="number" min="0" value={quantity} onChange={(e) => setQuantity(e.target.value)} className={inputCls()} />
          </Field>
        )}
      </div>
      <Field label="Reorder Level (low stock threshold)">
        <input type="number" min="0" value={reorderLevel} onChange={(e) => setReorderLevel(e.target.value)} className={inputCls()} />
      </Field>
      <Field label="Notes (optional)">
        <input value={notes} onChange={(e) => setNotes(e.target.value)} className={inputCls()} />
      </Field>
    </Modal>
  );
}

function StockInModal({ item, onClose, onSave }) {
  const [qty, setQty] = useState("");
  const [date, setDate] = useState(todayStr());
  const [note, setNote] = useState("");
  const [cost, setCost] = useState("");
  const [recordExpense, setRecordExpense] = useState(true);

  const submit = () => {
    if (!qty || Number(qty) <= 0) return;
    onSave({ itemId: item.id, qty: Number(qty), date, note, cost: cost ? Number(cost) : 0, recordExpense });
  };

  return (
    <Modal title={`Stock In \u2014 ${item.name}`} onClose={onClose} footer={<><button onClick={onClose} className={btnGhost}>Cancel</button><button onClick={submit} className={btnPrimary}>Record</button></>}>
      <p className="text-xs text-stone-500 mb-3">Current stock: <strong className="text-stone-800">{item.quantity} {item.unit}</strong></p>
      <Field label="Quantity Added"><input type="number" min="1" value={qty} onChange={(e) => setQty(e.target.value)} className={inputCls()} autoFocus /></Field>
      <Field label="Date"><input type="date" value={date} onChange={(e) => setDate(e.target.value)} className={inputCls()} /></Field>
      <Field label="Supplier / Note (optional)"><input value={note} onChange={(e) => setNote(e.target.value)} className={inputCls()} /></Field>
      <Field label="Cost (PHP, optional)"><input type="number" min="0" step="0.01" value={cost} onChange={(e) => setCost(e.target.value)} className={inputCls()} placeholder="0.00" /></Field>
      {Number(cost) > 0 && (
        <label className="flex items-center gap-2 text-sm text-stone-600">
          <input type="checkbox" checked={recordExpense} onChange={(e) => setRecordExpense(e.target.checked)} />
          Record as Cash Out expense
        </label>
      )}
    </Modal>
  );
}

function StockOutModal({ item, reasons, allowSaleIncome, onClose, onSave }) {
  const [qty, setQty] = useState("");
  const [date, setDate] = useState(todayStr());
  const [reason, setReason] = useState(reasons[0]);
  const [note, setNote] = useState("");
  const [amount, setAmount] = useState("");
  const [recordIncome, setRecordIncome] = useState(true);

  const submit = () => {
    if (!qty || Number(qty) <= 0) return;
    if (Number(qty) > Number(item.quantity)) return;
    onSave({ itemId: item.id, qty: Number(qty), date, reason, note, amount: amount ? Number(amount) : 0, recordIncome });
  };

  return (
    <Modal title={`Stock Out \u2014 ${item.name}`} onClose={onClose} footer={<><button onClick={onClose} className={btnGhost}>Cancel</button><button onClick={submit} className={btnPrimary}>Record</button></>}>
      <p className="text-xs text-stone-500 mb-3">Current stock: <strong className="text-stone-800">{item.quantity} {item.unit}</strong></p>
      <Field label="Quantity Removed"><input type="number" min="1" max={item.quantity} value={qty} onChange={(e) => setQty(e.target.value)} className={inputCls()} autoFocus /></Field>
      <Field label="Date"><input type="date" value={date} onChange={(e) => setDate(e.target.value)} className={inputCls()} /></Field>
      <Field label="Reason">
        <select value={reason} onChange={(e) => setReason(e.target.value)} className={inputCls()}>
          {reasons.map((r) => <option key={r} value={r}>{r}</option>)}
        </select>
      </Field>
      <Field label="Note (optional)"><input value={note} onChange={(e) => setNote(e.target.value)} className={inputCls()} /></Field>
      {allowSaleIncome && reason === "Sold" && (
        <>
          <Field label="Sale Amount (PHP)"><input type="number" min="0" step="0.01" value={amount} onChange={(e) => setAmount(e.target.value)} className={inputCls()} /></Field>
          {Number(amount) > 0 && (
            <label className="flex items-center gap-2 text-sm text-stone-600">
              <input type="checkbox" checked={recordIncome} onChange={(e) => setRecordIncome(e.target.checked)} />
              Record as Cash In income
            </label>
          )}
        </>
      )}
    </Modal>
  );
}

function InventoryModule({ title, icon: Icon, data, setData, cashOutCategory, cashInCategory, allowSaleIncome, reasonsOut, unitOptions, addTransaction, notify, askConfirm }) {
  const [search, setSearch] = useState("");
  const [addOpen, setAddOpen] = useState(false);
  const [editItem, setEditItem] = useState(null);
  const [stockInItem, setStockInItem] = useState(null);
  const [stockOutItem, setStockOutItem] = useState(null);
  const [logFilterItem, setLogFilterItem] = useState("all");
  const [logFilterType, setLogFilterType] = useState("all");

  const items = data.items || [];
  const log = data.log || [];

  const filteredItems = items.filter((i) => i.name.toLowerCase().includes(search.toLowerCase()));
  const lowItems = items.filter((i) => Number(i.quantity) <= Number(i.reorderLevel));

  const addItem = (item) => {
    setData((d) => ({ ...d, items: [...(d.items || []), { id: uid(), quantity: 0, ...item }] }));
    notify(`${title} added`);
    setAddOpen(false);
  };

  const saveEdit = (id, patch) => {
    setData((d) => ({ ...d, items: (d.items || []).map((i) => (i.id === id ? { ...i, ...patch } : i)) }));
    notify(`${title} updated`);
    setEditItem(null);
  };

  const deleteItem = (id) => {
    askConfirm(`Remove this ${title.toLowerCase()} item? Its movement history will be kept.`, () => {
      setData((d) => ({ ...d, items: (d.items || []).filter((i) => i.id !== id) }));
      notify(`${title} removed`);
    });
  };

  const doStockIn = ({ itemId, qty, date, note, cost, recordExpense }) => {
    const item = items.find((i) => i.id === itemId);
    if (!item) return;
    setData((d) => ({
      items: (d.items || []).map((i) => (i.id === itemId ? { ...i, quantity: Number(i.quantity) + Number(qty) } : i)),
      log: [{ id: uid(), itemId, itemName: item.name, type: "in", qty: Number(qty), date, note, amount: cost ? Number(cost) : 0, createdAt: Date.now() }, ...(d.log || [])],
    }));
    if (cost && Number(cost) > 0 && recordExpense) {
      addTransaction({ type: "out", category: cashOutCategory, amount: Number(cost), date, description: `${title} In - ${item.name} (${qty} ${item.unit || ""})` });
    }
    notify(`Stock in recorded for ${item.name}`);
    setStockInItem(null);
  };

  const doStockOut = ({ itemId, qty, date, reason, note, amount, recordIncome }) => {
    const item = items.find((i) => i.id === itemId);
    if (!item) return;
    if (Number(qty) > Number(item.quantity)) { notify("Quantity exceeds current stock", "error"); return; }
    setData((d) => ({
      items: (d.items || []).map((i) => (i.id === itemId ? { ...i, quantity: Number(i.quantity) - Number(qty) } : i)),
      log: [{ id: uid(), itemId, itemName: item.name, type: "out", qty: Number(qty), date, reason, note, amount: amount ? Number(amount) : 0, createdAt: Date.now() }, ...(d.log || [])],
    }));
    if (allowSaleIncome && reason === "Sold" && amount && Number(amount) > 0 && recordIncome) {
      addTransaction({ type: "in", category: cashInCategory, amount: Number(amount), date, description: `${item.name} sold (${qty} ${item.unit || ""})` });
    }
    notify(`Stock out recorded for ${item.name}`);
    setStockOutItem(null);
  };

  const filteredLog = log
    .filter((l) => (logFilterItem === "all" || l.itemId === logFilterItem) && (logFilterType === "all" || l.type === logFilterType))
    .sort((a, b) => (b.date + String(b.createdAt || 0)).localeCompare(a.date + String(a.createdAt || 0)));

  const exportCsv = () => {
    downloadCSV(`${title.toLowerCase()}_inventory_${todayStr()}.csv`, [
      ["Item", "Unit", "Quantity", "Reorder Level", "Status"],
      ...items.map((i) => [i.name, i.unit, i.quantity, i.reorderLevel, Number(i.quantity) <= Number(i.reorderLevel) ? "Low Stock" : "OK"]),
    ]);
  };

  return (
    <div className="space-y-5">
      {lowItems.length > 0 && (
        <div className="flex items-center gap-2 bg-amber-50 border border-amber-200 text-amber-800 rounded-xl px-4 py-3 text-sm">
          <AlertTriangle size={16} className="shrink-0" />
          <span>{lowItems.length} {title.toLowerCase()} item{lowItems.length > 1 ? "s are" : " is"} at or below reorder level.</span>
        </div>
      )}

      <div className="bg-white rounded-2xl border border-stone-200 shadow-sm">
        <div className="flex flex-wrap items-center gap-2 p-4 border-b border-stone-100">
          <div className="relative flex-1">
            <Search size={15} className="absolute left-2.5 top-2.5 text-stone-400" />
            <input value={search} onChange={(e) => setSearch(e.target.value)} placeholder={`Search ${title.toLowerCase()}`} className={inputCls() + " pl-8"} />
          </div>
          <button onClick={exportCsv} className={btnGhost}><Download size={15} />Export</button>
          <button onClick={() => setAddOpen(true)} className={btnPrimary}><Plus size={16} />Add {title}</button>
        </div>
        <div className="overflow-x-auto">
          {filteredItems.length === 0 ? (
            <EmptyState icon={Icon} text={`No ${title.toLowerCase()} items yet.`} />
          ) : (
            <table className="w-full text-sm">
              <thead>
                <tr className="text-left text-xs text-stone-500 uppercase">
                  <th className="px-4 py-2">Name</th><th className="px-4 py-2">Quantity</th><th className="px-4 py-2">Unit</th><th className="px-4 py-2">Reorder Level</th><th className="px-4 py-2">Status</th><th className="px-4 py-2"></th>
                </tr>
              </thead>
              <tbody>
                {filteredItems.map((i) => {
                  const low = Number(i.quantity) <= Number(i.reorderLevel);
                  return (
                    <tr key={i.id} className={`border-t border-stone-100 ${low ? "bg-amber-50" : "hover:bg-stone-50"}`}>
                      <td className="px-4 py-2.5 font-medium text-stone-900">{i.name}</td>
                      <td className={`px-4 py-2.5 font-semibold ${low ? "text-red-600" : "text-stone-800"}`}>{i.quantity}</td>
                      <td className="px-4 py-2.5 text-stone-500">{i.unit || "\u2014"}</td>
                      <td className="px-4 py-2.5 text-stone-500">{i.reorderLevel}</td>
                      <td className="px-4 py-2.5">{low ? <Badge tone="red">Low Stock</Badge> : <Badge tone="green">In Stock</Badge>}</td>
                      <td className="px-4 py-2.5">
                        <div className="flex items-center gap-1 justify-end">
                          <button onClick={() => setStockInItem(i)} className={btnIcon} title="Stock In"><ArrowUpCircle size={16} className="text-emerald-600" /></button>
                          <button onClick={() => setStockOutItem(i)} className={btnIcon} title="Stock Out"><ArrowDownCircle size={16} className="text-red-600" /></button>
                          <button onClick={() => setEditItem(i)} className={btnIcon}><Pencil size={14} /></button>
                          <button onClick={() => deleteItem(i.id)} className={btnIcon}><Trash2 size={14} /></button>
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          )}
        </div>
      </div>

      <div className="bg-white rounded-2xl border border-stone-200 shadow-sm">
        <div className="flex flex-wrap items-center gap-2 p-4 border-b border-stone-100">
          <h3 className="font-serif text-base text-stone-900 mr-auto">Movement Log</h3>
          <select value={logFilterItem} onChange={(e) => setLogFilterItem(e.target.value)} className={inputCls("w-auto")}>
            <option value="all">All Items</option>
            {items.map((i) => <option key={i.id} value={i.id}>{i.name}</option>)}
          </select>
          <select value={logFilterType} onChange={(e) => setLogFilterType(e.target.value)} className={inputCls("w-auto")}>
            <option value="all">All Movements</option>
            <option value="in">Stock In</option>
            <option value="out">Stock Out</option>
          </select>
        </div>
        <div className="overflow-x-auto overflow-y-auto max-h-80">
          {filteredLog.length === 0 ? (
            <EmptyState icon={Clock} text="No movement recorded yet." />
          ) : (
            <table className="w-full text-sm">
              <thead>
                <tr className="text-left text-xs text-stone-500 uppercase sticky top-0 bg-white">
                  <th className="px-4 py-2">Date</th><th className="px-4 py-2">Item</th><th className="px-4 py-2">Movement</th><th className="px-4 py-2">Qty</th><th className="px-4 py-2">Reason / Note</th>
                </tr>
              </thead>
              <tbody>
                {filteredLog.map((l) => (
                  <tr key={l.id} className="border-t border-stone-100">
                    <td className="px-4 py-2.5 whitespace-nowrap">{fmtDate(l.date)}</td>
                    <td className="px-4 py-2.5">{l.itemName}</td>
                    <td className="px-4 py-2.5">{l.type === "in" ? <span className="text-emerald-600">Stock In</span> : <span className="text-red-600">Stock Out</span>}</td>
                    <td className="px-4 py-2.5">{l.qty}</td>
                    <td className="px-4 py-2.5 text-stone-500">{l.reason ? `${l.reason}${l.note ? " \u2014 " + l.note : ""}` : l.note || "\u2014"}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </div>

      {addOpen && <ItemFormModal title={`Add ${title}`} unitOptions={unitOptions} onClose={() => setAddOpen(false)} onSave={addItem} />}
      {editItem && <ItemFormModal title={`Edit ${title}`} unitOptions={unitOptions} initial={editItem} hideQuantity onClose={() => setEditItem(null)} onSave={(patch) => saveEdit(editItem.id, patch)} />}
      {stockInItem && <StockInModal item={stockInItem} onClose={() => setStockInItem(null)} onSave={doStockIn} />}
      {stockOutItem && <StockOutModal item={stockOutItem} reasons={reasonsOut} allowSaleIncome={allowSaleIncome} onClose={() => setStockOutItem(null)} onSave={doStockOut} />}
    </div>
  );
}

/* ============================== Attendance ============================== */

function EmployeeModal({ initial, onClose, onSave }) {
  const [name, setName] = useState(initial?.name || "");
  const [position, setPosition] = useState(initial?.position || "");
  const [dailyRate, setDailyRate] = useState(initial?.dailyRate ?? "");
  const [contact, setContact] = useState(initial?.contact || "");
  const [dateHired, setDateHired] = useState(initial?.dateHired || todayStr());

  const submit = () => {
    if (!name.trim() || !dailyRate) return;
    onSave({ name: name.trim(), position, dailyRate: Number(dailyRate), contact, dateHired });
  };

  return (
    <Modal title={initial ? "Edit Employee" : "Add Employee"} onClose={onClose} footer={<><button onClick={onClose} className={btnGhost}>Cancel</button><button onClick={submit} className={btnPrimary}>Save</button></>}>
      <Field label="Full Name"><input value={name} onChange={(e) => setName(e.target.value)} className={inputCls()} autoFocus /></Field>
      <Field label="Position"><input value={position} onChange={(e) => setPosition(e.target.value)} className={inputCls()} placeholder="e.g. Aesthetician, Receptionist" /></Field>
      <Field label="Daily Rate (PHP)"><input type="number" min="0" step="0.01" value={dailyRate} onChange={(e) => setDailyRate(e.target.value)} className={inputCls()} /></Field>
      <Field label="Contact Number"><input value={contact} onChange={(e) => setContact(e.target.value)} className={inputCls()} /></Field>
      <Field label="Date Hired"><input type="date" value={dateHired} onChange={(e) => setDateHired(e.target.value)} className={inputCls()} /></Field>
    </Modal>
  );
}

function RecordModal({ initial, employees, onClose, onSave }) {
  const [employeeId, setEmployeeId] = useState(initial?.employeeId || employees[0]?.id || "");
  const [date, setDate] = useState(initial?.date || todayStr());
  const [timeIn, setTimeIn] = useState(initial?.timeIn || "");
  const [timeOut, setTimeOut] = useState(initial?.timeOut || "");
  const [status, setStatus] = useState(initial?.status || "Present");
  const [holidayType, setHolidayType] = useState(initial?.holidayType || "None");

  const timeDisabled = NO_TIME_STATUSES.includes(status);

  useEffect(() => {
    if (timeDisabled) {
      setTimeIn("");
      setTimeOut("");
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [timeDisabled]);

  const submit = () => {
    if (!employeeId) return;
    onSave({ employeeId, date, timeIn: timeDisabled ? "" : timeIn, timeOut: timeDisabled ? "" : timeOut, status, holidayType });
  };

  return (
    <Modal title={initial ? "Edit Attendance" : "Add Attendance"} onClose={onClose} footer={<><button onClick={onClose} className={btnGhost}>Cancel</button><button onClick={submit} className={btnPrimary}>Save</button></>}>
      <Field label="Employee">
        <select value={employeeId} onChange={(e) => setEmployeeId(e.target.value)} className={inputCls()}>
          {employees.map((e) => <option key={e.id} value={e.id}>{e.name}</option>)}
        </select>
      </Field>
      <Field label="Date"><input type="date" value={date} onChange={(e) => setDate(e.target.value)} className={inputCls()} /></Field>
      <Field label="Status">
        <select value={status} onChange={(e) => setStatus(e.target.value)} className={inputCls()}>
          {ATT_STATUSES.map((s) => <option key={s} value={s}>{s}</option>)}
        </select>
      </Field>
      <div className="grid grid-cols-2 gap-3">
        <Field label="Time In">
          <input
            type="time"
            value={timeIn}
            onChange={(e) => setTimeIn(e.target.value)}
            disabled={timeDisabled}
            className={inputCls() + (timeDisabled ? " bg-stone-100 text-stone-400 cursor-not-allowed" : "")}
          />
        </Field>
        <Field label="Time Out">
          <input
            type="time"
            value={timeOut}
            onChange={(e) => setTimeOut(e.target.value)}
            disabled={timeDisabled}
            className={inputCls() + (timeDisabled ? " bg-stone-100 text-stone-400 cursor-not-allowed" : "")}
          />
        </Field>
      </div>
      {timeDisabled && (
        <p className="text-xs text-stone-500 -mt-2 mb-3">Time In / Time Out isn't applicable for "{status}".</p>
      )}
      <Field label="Holiday">
        <div className="flex flex-wrap gap-4">
          <label className="flex items-center gap-2 text-sm text-stone-700">
            <input
              type="checkbox"
              checked={holidayType === "Regular Holiday"}
              onChange={() => setHolidayType((h) => (h === "Regular Holiday" ? "None" : "Regular Holiday"))}
            />
            Regular Holiday (x2 pay)
          </label>
          <label className="flex items-center gap-2 text-sm text-stone-700">
            <input
              type="checkbox"
              checked={holidayType === "Special Holiday"}
              onChange={() => setHolidayType((h) => (h === "Special Holiday" ? "None" : "Special Holiday"))}
            />
            Special Holiday (x1.30 pay)
          </label>
        </div>
      </Field>
    </Modal>
  );
}

function LeaveCreditsPanel({ employees, attendance }) {
  const [year, setYear] = useState(new Date().getFullYear());
  const activeEmployees = employees.filter((e) => e.status === "Active");

  const rows = activeEmployees.map((emp) => {
    const recs = attendance.filter((a) => a.employeeId === emp.id && a.date.slice(0, 4) === String(year));
    const sickUsed = recs.filter((a) => a.status === "Paid Sick Leave").length;
    const vacUsed = recs.filter((a) => a.status === "Paid Vacation Leave").length;
    return { employee: emp, sickUsed, vacUsed };
  });

  const leaveBadge = (used, allowance) => {
    if (used > allowance) return <Badge tone="red">{used} / {allowance} \u2014 exceeded</Badge>;
    if (used === allowance) return <Badge tone="amber">{used} / {allowance} \u2014 fully used</Badge>;
    return <Badge tone="green">{used} / {allowance} used</Badge>;
  };

  return (
    <div className="bg-white rounded-2xl border border-stone-200 shadow-sm">
      <div className="flex flex-wrap items-center gap-2 p-4 border-b border-stone-100">
        <h3 className="font-serif text-base text-stone-900 mr-auto">Paid Leave Credits</h3>
        <input type="number" value={year} onChange={(e) => setYear(Number(e.target.value) || year)} className={inputCls("w-28")} />
      </div>
      <p className="px-4 pt-3 text-xs text-stone-500">
        Each active employee is allotted {SICK_LEAVE_ALLOWANCE} paid Sick Leave days and {VACATION_LEAVE_ALLOWANCE} paid Vacation Leave days per year, tracked from "Paid Sick Leave" / "Paid Vacation Leave" entries in Time Records.
      </p>
      <div className="overflow-x-auto">
        {rows.length === 0 ? (
          <EmptyState icon={Users} text="No active employees." />
        ) : (
          <table className="w-full text-sm">
            <thead>
              <tr className="text-left text-xs text-stone-500 uppercase">
                <th className="px-4 py-2">Employee</th><th className="px-4 py-2">Sick Leave</th><th className="px-4 py-2">Vacation Leave</th>
              </tr>
            </thead>
            <tbody>
              {rows.map((r) => (
                <tr key={r.employee.id} className="border-t border-stone-100">
                  <td className="px-4 py-2.5 font-medium text-stone-900">{r.employee.name}</td>
                  <td className="px-4 py-2.5">{leaveBadge(r.sickUsed, SICK_LEAVE_ALLOWANCE)}</td>
                  <td className="px-4 py-2.5">{leaveBadge(r.vacUsed, VACATION_LEAVE_ALLOWANCE)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
}

function AttendanceSection({ employees, setEmployees, attendance, setAttendance, notify, askConfirm }) {
  const [tab, setTab] = useState("employees");
  const [empModalOpen, setEmpModalOpen] = useState(false);
  const [editEmp, setEditEmp] = useState(null);
  const [recModalOpen, setRecModalOpen] = useState(false);
  const [editRec, setEditRec] = useState(null);
  const [quickEmp, setQuickEmp] = useState("");
  const [filterEmp, setFilterEmp] = useState("all");
  const [from, setFrom] = useState(addDays(todayStr(), -13));
  const [to, setTo] = useState(todayStr());

  const activeEmployees = employees.filter((e) => e.status === "Active");

  const saveEmployee = (emp) => {
    if (editEmp) {
      setEmployees((prev) => prev.map((e) => (e.id === editEmp.id ? { ...e, ...emp } : e)));
      notify("Employee updated");
    } else {
      setEmployees((prev) => [...prev, { id: uid(), status: "Active", ...emp }]);
      notify("Employee added");
    }
    setEmpModalOpen(false);
    setEditEmp(null);
  };

  const toggleStatus = (emp) => {
    setEmployees((prev) => prev.map((e) => (e.id === emp.id ? { ...e, status: e.status === "Active" ? "Inactive" : "Active" } : e)));
  };

  const deleteEmployee = (id) => {
    askConfirm("Remove this employee? Their attendance history will be kept.", () => {
      setEmployees((prev) => prev.filter((e) => e.id !== id));
      notify("Employee removed");
    });
  };

  const upsertRecord = (rec) => {
    if (editRec) {
      setAttendance((prev) => prev.map((r) => (r.id === editRec.id ? { ...r, ...rec } : r)));
      notify("Attendance updated");
    } else {
      setAttendance((prev) => [{ id: uid(), ...rec }, ...prev]);
      notify("Attendance recorded");
    }
    setRecModalOpen(false);
    setEditRec(null);
  };

  const deleteRecord = (id) => {
    askConfirm("Delete this attendance record?", () => {
      setAttendance((prev) => prev.filter((r) => r.id !== id));
      notify("Record deleted");
    });
  };

  const quickClock = (field) => {
    if (!quickEmp) { notify("Select an employee first", "error"); return; }
    const today = todayStr();
    const time = nowTime();
    const existing = attendance.find((r) => r.employeeId === quickEmp && r.date === today);
    if (existing) {
      setAttendance((prev) => prev.map((r) => (r.id === existing.id ? { ...r, [field]: time, status: r.status || "Present" } : r)));
    } else {
      setAttendance((prev) => [{ id: uid(), employeeId: quickEmp, date: today, timeIn: field === "timeIn" ? time : "", timeOut: field === "timeOut" ? time : "", status: "Present", holidayType: "None" }, ...prev]);
    }
    notify(field === "timeIn" ? "Timed in" : "Timed out");
  };

  const filteredRecords = attendance
    .filter((r) => (filterEmp === "all" || r.employeeId === filterEmp) && r.date >= from && r.date <= to)
    .sort((a, b) => b.date.localeCompare(a.date));

  const empName = (id) => employees.find((e) => e.id === id)?.name || "Unknown";

  const exportCsv = () => {
    downloadCSV(`attendance_${todayStr()}.csv`, [
      ["Date", "Employee", "Time In", "Time Out", "Hours", "Status", "Holiday Type"],
      ...filteredRecords.map((r) => [r.date, empName(r.employeeId), r.timeIn, r.timeOut, hoursBetween(r.timeIn, r.timeOut), r.status, r.holidayType && r.holidayType !== "None" ? r.holidayType : ""]),
    ]);
  };

  return (
    <div className="space-y-5">
      <div className="flex gap-2 bg-white p-1 rounded-xl border border-stone-200 w-fit flex-wrap">
        <button onClick={() => setTab("employees")} className={`px-4 py-1.5 rounded-lg text-sm font-medium ${tab === "employees" ? "bg-rose-500 text-white" : "text-stone-600"}`}>Employees</button>
        <button onClick={() => setTab("records")} className={`px-4 py-1.5 rounded-lg text-sm font-medium ${tab === "records" ? "bg-rose-500 text-white" : "text-stone-600"}`}>Time Records</button>
        <button onClick={() => setTab("leave")} className={`px-4 py-1.5 rounded-lg text-sm font-medium ${tab === "leave" ? "bg-rose-500 text-white" : "text-stone-600"}`}>Leave Credits</button>
      </div>

      {tab === "employees" && (
        <div className="bg-white rounded-2xl border border-stone-200 shadow-sm">
          <div className="flex items-center justify-between p-4 border-b border-stone-100">
            <h3 className="font-serif text-base text-stone-900">Employee Records</h3>
            <button onClick={() => { setEditEmp(null); setEmpModalOpen(true); }} className={btnPrimary}><Plus size={16} />Add Employee</button>
          </div>
          <div className="overflow-x-auto">
            {employees.length === 0 ? (
              <EmptyState icon={Users} text="No employees added yet." />
            ) : (
              <table className="w-full text-sm">
                <thead>
                  <tr className="text-left text-xs text-stone-500 uppercase">
                    <th className="px-4 py-2">Name</th><th className="px-4 py-2">Position</th><th className="px-4 py-2">Daily Rate</th><th className="px-4 py-2">Contact</th><th className="px-4 py-2">Date Hired</th><th className="px-4 py-2">Status</th><th className="px-4 py-2"></th>
                  </tr>
                </thead>
                <tbody>
                  {employees.map((e) => (
                    <tr key={e.id} className="border-t border-stone-100">
                      <td className="px-4 py-2.5 font-medium text-stone-900">{e.name}</td>
                      <td className="px-4 py-2.5 text-stone-600">{e.position || "\u2014"}</td>
                      <td className="px-4 py-2.5 text-stone-600">{peso(e.dailyRate)}</td>
                      <td className="px-4 py-2.5 text-stone-500">{e.contact || "\u2014"}</td>
                      <td className="px-4 py-2.5 text-stone-500">{fmtDate(e.dateHired)}</td>
                      <td className="px-4 py-2.5">{e.status === "Active" ? <Badge tone="green">Active</Badge> : <Badge tone="neutral">Inactive</Badge>}</td>
                      <td className="px-4 py-2.5">
                        <div className="flex items-center gap-1 justify-end">
                          <button onClick={() => toggleStatus(e)} className={btnIcon} title="Toggle Active/Inactive"><CheckCircle2 size={14} /></button>
                          <button onClick={() => { setEditEmp(e); setEmpModalOpen(true); }} className={btnIcon}><Pencil size={14} /></button>
                          <button onClick={() => deleteEmployee(e.id)} className={btnIcon}><Trash2 size={14} /></button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}
          </div>
        </div>
      )}

      {tab === "records" && (
        <div className="space-y-4">
          <div className="bg-white rounded-2xl border border-stone-200 shadow-sm p-4 flex flex-wrap items-center gap-2">
            <Clock size={16} className="text-rose-500" />
            <span className="text-sm text-stone-600 mr-1">Quick Clock:</span>
            <select value={quickEmp} onChange={(e) => setQuickEmp(e.target.value)} className={inputCls("w-auto")}>
              <option value="">Select employee</option>
              {activeEmployees.map((e) => <option key={e.id} value={e.id}>{e.name}</option>)}
            </select>
            <button onClick={() => quickClock("timeIn")} className={btnGhost}><LogIn size={15} />Time In</button>
            <button onClick={() => quickClock("timeOut")} className={btnGhost}><ArrowDownCircle size={15} />Time Out</button>
            <button onClick={() => { setEditRec(null); setRecModalOpen(true); }} className={btnPrimary + " ml-auto"}><Plus size={16} />Add Record</button>
          </div>

          <div className="bg-white rounded-2xl border border-stone-200 shadow-sm">
            <div className="flex flex-wrap items-center gap-2 p-4 border-b border-stone-100">
              <select value={filterEmp} onChange={(e) => setFilterEmp(e.target.value)} className={inputCls("w-auto")}>
                <option value="all">All Employees</option>
                {employees.map((e) => <option key={e.id} value={e.id}>{e.name}</option>)}
              </select>
              <input type="date" value={from} onChange={(e) => setFrom(e.target.value)} className={inputCls("w-auto")} />
              <input type="date" value={to} onChange={(e) => setTo(e.target.value)} className={inputCls("w-auto")} />
              <button onClick={exportCsv} className={btnGhost + " ml-auto"}><Download size={15} />Export</button>
            </div>
            <div className="overflow-x-auto">
              {filteredRecords.length === 0 ? (
                <EmptyState icon={Clock} text="No attendance records for this range." />
              ) : (
                <table className="w-full text-sm">
                  <thead>
                    <tr className="text-left text-xs text-stone-500 uppercase">
                      <th className="px-4 py-2">Date</th><th className="px-4 py-2">Employee</th><th className="px-4 py-2">Time In</th><th className="px-4 py-2">Time Out</th><th className="px-4 py-2">Hours</th><th className="px-4 py-2">Status</th><th className="px-4 py-2">Day Type</th><th className="px-4 py-2"></th>
                    </tr>
                  </thead>
                  <tbody>
                    {filteredRecords.map((r) => (
                      <tr key={r.id} className="border-t border-stone-100">
                        <td className="px-4 py-2.5 whitespace-nowrap">{fmtDate(r.date)}</td>
                        <td className="px-4 py-2.5 font-medium text-stone-900">{empName(r.employeeId)}</td>
                        <td className="px-4 py-2.5">{fmtTime(r.timeIn)}</td>
                        <td className="px-4 py-2.5">{fmtTime(r.timeOut)}</td>
                        <td className="px-4 py-2.5">{hoursBetween(r.timeIn, r.timeOut) || "\u2014"}</td>
                        <td className="px-4 py-2.5">
                          <Badge
                            tone={
                              r.status === "Present" ? "green" :
                              r.status === "Absent" ? "red" :
                              r.status === "Late" ? "amber" :
                              (r.status === "Paid Sick Leave" || r.status === "Paid Vacation Leave") ? "rose" :
                              "neutral"
                            }
                          >
                            {r.status}
                          </Badge>
                        </td>
                        <td className="px-4 py-2.5">
                          {r.holidayType && r.holidayType !== "None" ? (
                            <Badge tone="amber">{r.holidayType === "Regular Holiday" ? "Regular Holiday x2" : "Special Holiday x1.30"}</Badge>
                          ) : (
                            <span className="text-stone-300">{"\u2014"}</span>
                          )}
                        </td>
                        <td className="px-4 py-2.5">
                          <div className="flex items-center gap-1 justify-end">
                            <button onClick={() => { setEditRec(r); setRecModalOpen(true); }} className={btnIcon}><Pencil size={14} /></button>
                            <button onClick={() => deleteRecord(r.id)} className={btnIcon}><Trash2 size={14} /></button>
                          </div>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              )}
            </div>
          </div>
        </div>
      )}

      {tab === "leave" && (
        <LeaveCreditsPanel employees={employees} attendance={attendance} />
      )}

      {empModalOpen && <EmployeeModal initial={editEmp} onClose={() => { setEmpModalOpen(false); setEditEmp(null); }} onSave={saveEmployee} />}
      {recModalOpen && <RecordModal initial={editRec} employees={employees} onClose={() => { setRecModalOpen(false); setEditRec(null); }} onSave={upsertRecord} />}
    </div>
  );
}

