function DeductionsModal({ employeeName, initial, onClose, onSave }) {
  const [sssEnabled, setSssEnabled] = useState(initial?.sssEnabled || false);
  const [sssAmount, setSssAmount] = useState(initial?.sssAmount ?? "");
  const [pagibigEnabled, setPagibigEnabled] = useState(initial?.pagibigEnabled || false);
  const [pagibigAmount, setPagibigAmount] = useState(initial?.pagibigAmount ?? "");
  const [otherAmount, setOtherAmount] = useState(initial?.otherAmount ?? "");

  const submit = () => {
    onSave({
      sssEnabled,
      sssAmount: sssEnabled ? Number(sssAmount) || 0 : 0,
      pagibigEnabled,
      pagibigAmount: pagibigEnabled ? Number(pagibigAmount) || 0 : 0,
      otherAmount: Number(otherAmount) || 0,
    });
  };

  return (
    <Modal title={`Deductions \u2014 ${employeeName}`} onClose={onClose} footer={<><button onClick={onClose} className={btnGhost}>Cancel</button><button onClick={submit} className={btnPrimary}>Save</button></>}>
      <Field label=" ">
        <label className="flex items-center gap-2 text-sm text-stone-700 mb-1">
          <input type="checkbox" checked={sssEnabled} onChange={(e) => setSssEnabled(e.target.checked)} />
          Include SSS Contribution
        </label>
        {sssEnabled && (
          <input type="number" min="0" step="0.01" value={sssAmount} onChange={(e) => setSssAmount(e.target.value)} className={inputCls()} placeholder="SSS amount (PHP)" />
        )}
      </Field>
      <Field label=" ">
        <label className="flex items-center gap-2 text-sm text-stone-700 mb-1">
          <input type="checkbox" checked={pagibigEnabled} onChange={(e) => setPagibigEnabled(e.target.checked)} />
          Include Pag-IBIG Contribution
        </label>
        {pagibigEnabled && (
          <input type="number" min="0" step="0.01" value={pagibigAmount} onChange={(e) => setPagibigAmount(e.target.value)} className={inputCls()} placeholder="Pag-IBIG amount (PHP)" />
        )}
      </Field>
      <Field label="Other Deductions (PHP)">
        <input type="number" min="0" step="0.01" value={otherAmount} onChange={(e) => setOtherAmount(e.target.value)} className={inputCls()} placeholder="0.00" />
      </Field>
    </Modal>
  );
}

