function ThirteenthMonthPanel({ employees, attendance, addTransaction, notify }) {
  const [year, setYear] = useState(new Date().getFullYear());
  const activeEmployees = employees.filter((e) => e.status === "Active");

  const rows = useMemo(() => {
    const yearStart = `${year}-01-01`;
    const yearEnd = `${year}-12-31`;
    return activeEmployees.map((emp) => {
      const recs = attendance.filter((a) => a.employeeId === emp.id && a.date >= yearStart && a.date <= yearEnd);
      let basicRegularTotal = 0;
      recs.forEach((r) => { basicRegularTotal += computeDayPay(r, emp.dailyRate).basicRegular; });
      basicRegularTotal = round2(basicRegularTotal);
      return { employee: emp, basicRegularTotal, thirteenth: round2(basicRegularTotal / 12) };
    });
  }, [activeEmployees, attendance, year]);

  const total = rows.reduce((a, b) => a + b.thirteenth, 0);

  const exportCsv = () => {
    downloadCSV(`13th_month_pay_${year}.csv`, [
      ["Employee", "Total Basic Salary Earned", "13th Month Pay"],
      ...rows.map((r) => [r.employee.name, r.basicRegularTotal, r.thirteenth]),
    ]);
  };

  const recordToCashOut = () => {
    const payable = rows.filter((r) => r.thirteenth > 0);
    if (payable.length === 0) { notify("No 13th month pay due for this year", "error"); return; }
    const note = payable.map((r) => `${r.employee.name}: ${peso(r.thirteenth)}`).join(" | ");
    addTransaction({ type: "out", category: "Payroll", amount: round2(total), date: todayStr(), description: `13th Month Pay ${year} \u2014 ${note}` });
    notify("13th month pay recorded to Cash Out");
  };

  return (
    <div className="bg-white rounded-2xl border border-stone-200 shadow-sm">
      <div className="flex flex-wrap items-center gap-2 p-4 border-b border-stone-100">
        <h3 className="font-serif text-base text-stone-900 mr-auto">13th Month Pay</h3>
        <input type="number" value={year} onChange={(e) => setYear(Number(e.target.value) || year)} className={inputCls("w-28")} />
        <button onClick={exportCsv} className={btnGhost}><Download size={15} />Export</button>
        <button onClick={recordToCashOut} className={btnPrimary}><Wallet size={16} />Record to Cash Out</button>
      </div>
      <p className="px-4 pt-3 text-xs text-stone-500">
        Computed as total basic salary earned for {year} \u00f7 12. Overtime pay and holiday premiums are excluded, in line with standard 13th month pay rules.
      </p>
      <div className="overflow-x-auto">
        {rows.length === 0 ? (
          <EmptyState icon={Calculator} text="No active employees." />
        ) : (
          <table className="w-full text-sm">
            <thead>
              <tr className="text-left text-xs text-stone-500 uppercase">
                <th className="px-4 py-2">Employee</th><th className="px-4 py-2">Basic Salary Earned ({year})</th><th className="px-4 py-2">13th Month Pay</th>
              </tr>
            </thead>
            <tbody>
              {rows.map((r) => (
                <tr key={r.employee.id} className="border-t border-stone-100">
                  <td className="px-4 py-2.5 font-medium text-stone-900">{r.employee.name}</td>
                  <td className="px-4 py-2.5 text-stone-600">{peso(r.basicRegularTotal)}</td>
                  <td className="px-4 py-2.5 font-semibold text-stone-900">{peso(r.thirteenth)}</td>
                </tr>
              ))}
            </tbody>
            <tfoot>
              <tr className="border-t-2 border-stone-200 font-semibold text-stone-900">
                <td className="px-4 py-2.5" colSpan={2}>Total</td>
                <td className="px-4 py-2.5">{peso(round2(total))}</td>
              </tr>
            </tfoot>
          </table>
        )}
      </div>
    </div>
  );
}

function PayrollSection({ employees, attendance, addTransaction, payrollRuns, setPayrollRuns, notify }) {
  const [periodType, setPeriodType] = useState("Monthly");
  const [start, setStart] = useState(startOfMonth(todayStr()));
  const [deductions, setDeductions] = useState({});
  const [payslip, setPayslip] = useState(null);
  const [historyOpen, setHistoryOpen] = useState(null);
  const [dedEmployee, setDedEmployee] = useState(null);

  const end = useMemo(() => {
    if (periodType === "Daily") return start;
    if (periodType === "Weekly") return addDays(start, 6);
    if (periodType === "Biweekly") return addDays(start, 13);
    return endOfMonth(start);
  }, [periodType, start]);

  const activeEmployees = employees.filter((e) => e.status === "Active");

  const rows = useMemo(() => {
    return activeEmployees.map((emp) => {
      const recs = attendance.filter((a) => a.employeeId === emp.id && a.date >= start && a.date <= end);
      let basicTotal = 0, otTotal = 0, otHoursTotal = 0, undertimeHoursTotal = 0, holidayDays = 0;
      recs.forEach((r) => {
        const c = computeDayPay(r, emp.dailyRate);
        basicTotal += c.basic;
        otTotal += c.otPay;
        otHoursTotal += c.otHours;
        undertimeHoursTotal += c.undertimeHours;
        if (r.holidayType && r.holidayType !== "None") holidayDays++;
      });
      basicTotal = round2(basicTotal);
      otTotal = round2(otTotal);
      otHoursTotal = round2(otHoursTotal);
      undertimeHoursTotal = round2(undertimeHoursTotal);
      const gross = round2(basicTotal + otTotal);
      const ded = deductions[emp.id] || { sssEnabled: false, sssAmount: 0, pagibigEnabled: false, pagibigAmount: 0, otherAmount: 0 };
      const dedTotal = round2((ded.sssEnabled ? ded.sssAmount : 0) + (ded.pagibigEnabled ? ded.pagibigAmount : 0) + (ded.otherAmount || 0));
      const net = Math.max(0, round2(gross - dedTotal));
      return { employee: emp, recs, basicTotal, otTotal, otHoursTotal, undertimeHoursTotal, holidayDays, gross, ded, deduction: dedTotal, net };
    });
  }, [activeEmployees, attendance, start, end, deductions]);

  const totalNet = round2(rows.reduce((a, b) => a + b.net, 0));

  const recordPayroll = () => {
    const payable = rows.filter((r) => r.net > 0);
    if (payable.length === 0) { notify("No payable salaries for this period", "error"); return; }
    const note = payable.map((r) => `${r.employee.name}: ${peso(r.net)}`).join(" | ");
    addTransaction({ type: "out", category: "Payroll", amount: totalNet, date: end, description: `Payroll (${periodType}) ${fmtDate(start)}\u2013${fmtDate(end)} \u2014 ${note}` });
    setPayrollRuns((prev) => [
      {
        id: uid(),
        periodType,
        start,
        end,
        rows: payable.map((r) => ({
          employeeId: r.employee.id, name: r.employee.name, dailyRate: r.employee.dailyRate,
          basicTotal: r.basicTotal, otTotal: r.otTotal, gross: r.gross, deduction: r.deduction, net: r.net,
        })),
        total: totalNet,
        processedAt: todayStr(),
      },
      ...prev,
    ]);
    notify("Payroll recorded to Cash Out");
  };

  const exportCsv = () => {
    downloadCSV(`payroll_${start}_to_${end}.csv`, [
      ["Employee", "Daily Rate", "Basic Pay", "Overtime Pay", "Gross Pay", "SSS", "Pag-IBIG", "Other Deductions", "Net Pay"],
      ...rows.map((r) => [r.employee.name, r.employee.dailyRate, r.basicTotal, r.otTotal, r.gross, r.ded.sssEnabled ? r.ded.sssAmount : 0, r.ded.pagibigEnabled ? r.ded.pagibigAmount : 0, r.ded.otherAmount || 0, r.net]),
    ]);
  };

  return (
    <div className="space-y-5">
      <div className="bg-white rounded-2xl border border-stone-200 shadow-sm p-4 flex flex-wrap items-end gap-3">
        <Field label="Period Type">
          <select value={periodType} onChange={(e) => setPeriodType(e.target.value)} className={inputCls("w-auto")}>
            {["Daily", "Weekly", "Biweekly", "Monthly"].map((p) => <option key={p} value={p}>{p}</option>)}
          </select>
        </Field>
        <Field label="Start Date">
          <input type="date" value={start} onChange={(e) => setStart(e.target.value)} className={inputCls("w-auto")} />
        </Field>
        <Field label="End Date">
          <input type="date" value={end} readOnly className={inputCls("w-auto") + " bg-stone-100"} />
        </Field>
        <button onClick={exportCsv} className={btnGhost}><Download size={15} />Export</button>
        <button onClick={recordPayroll} className={btnPrimary}><Wallet size={16} />Record to Cash Out</button>
      </div>
      <p className="text-xs text-stone-500 px-1">
        Basic pay is computed from attendance: an 8-hour day is standard, and undertime/overtime only kick in once the difference reaches 30 minutes (smaller gaps are paid as a normal full day). Undertime is pro-rated against the hourly rate, overtime pays 125% of the hourly rate, and holiday-flagged days are paid at x2 (Regular) or x1.30 (Special).
      </p>

      <div className="bg-white rounded-2xl border border-stone-200 shadow-sm overflow-x-auto">
        {rows.length === 0 ? (
          <EmptyState icon={Calculator} text="No active employees to compute payroll for." />
        ) : (
          <table className="w-full text-sm">
            <thead>
              <tr className="text-left text-xs text-stone-500 uppercase">
                <th className="px-4 py-2">Employee</th><th className="px-4 py-2">Daily Rate</th><th className="px-4 py-2">Basic Pay</th><th className="px-4 py-2">Overtime</th><th className="px-4 py-2">Gross Pay</th><th className="px-4 py-2">Deductions</th><th className="px-4 py-2">Net Pay</th><th className="px-4 py-2"></th>
              </tr>
            </thead>
            <tbody>
              {rows.map((r) => (
                <tr key={r.employee.id} className="border-t border-stone-100">
                  <td className="px-4 py-2.5 font-medium text-stone-900">{r.employee.name}</td>
                  <td className="px-4 py-2.5 text-stone-600">{peso(r.employee.dailyRate)}</td>
                  <td className="px-4 py-2.5 text-stone-600">{peso(r.basicTotal)}</td>
                  <td className="px-4 py-2.5 text-stone-600">{r.otTotal > 0 ? peso(r.otTotal) : "\u2014"}</td>
                  <td className="px-4 py-2.5 text-stone-600">{peso(r.gross)}</td>
                  <td className="px-4 py-2.5">
                    <button onClick={() => setDedEmployee(r)} className={btnGhost}>
                      {r.deduction > 0 ? peso(r.deduction) : "Set"}
                    </button>
                  </td>
                  <td className="px-4 py-2.5 font-semibold text-stone-900">{peso(r.net)}</td>
                  <td className="px-4 py-2.5"><button onClick={() => setPayslip(r)} className={btnGhost}><Printer size={14} />Payslip</button></td>
                </tr>
              ))}
            </tbody>
            <tfoot>
              <tr className="border-t-2 border-stone-200 font-semibold text-stone-900">
                <td className="px-4 py-2.5" colSpan={6}>Total</td>
                <td className="px-4 py-2.5">{peso(totalNet)}</td>
                <td></td>
              </tr>
            </tfoot>
          </table>
        )}
      </div>

      <div className="bg-white rounded-2xl border border-stone-200 shadow-sm">
        <div className="px-4 py-3 border-b border-stone-100"><h3 className="font-serif text-base text-stone-900">Payroll History</h3></div>
        {payrollRuns.length === 0 ? (
          <EmptyState icon={Calculator} text="No payroll has been processed yet." />
        ) : (
          <ul className="divide-y divide-stone-100">
            {payrollRuns.map((run) => (
              <li key={run.id} className="px-4 py-3 flex items-center justify-between text-sm gap-2">
                <div className="min-w-0 truncate">
                  <span className="font-medium text-stone-900">{run.periodType}</span>
                  <span className="text-stone-500"> \u00b7 {fmtDate(run.start)} \u2013 {fmtDate(run.end)} \u00b7 {run.rows.length} employee(s)</span>
                </div>
                <div className="flex items-center gap-3 shrink-0">
                  <span className="font-semibold text-stone-900">{peso(run.total)}</span>
                  <button onClick={() => setHistoryOpen(run)} className="text-xs text-rose-600 hover:underline">View</button>
                </div>
              </li>
            ))}
          </ul>
        )}
      </div>

      <ThirteenthMonthPanel employees={employees} attendance={attendance} addTransaction={addTransaction} notify={notify} />

      {payslip && <PayslipModal row={payslip} periodType={periodType} start={start} end={end} onClose={() => setPayslip(null)} />}
      {historyOpen && <PayrollRunModal run={historyOpen} onClose={() => setHistoryOpen(null)} />}
      {dedEmployee && (
        <DeductionsModal
          employeeName={dedEmployee.employee.name}
          initial={dedEmployee.ded}
          onClose={() => setDedEmployee(null)}
          onSave={(val) => { setDeductions((d) => ({ ...d, [dedEmployee.employee.id]: val })); setDedEmployee(null); }}
        />
      )}
    </div>
  );
}

