function ClinicApp({ session }) {
  const [transactions, setTransactions, l1] = useSupabaseState("jsj-transactions", []);
  const [medications, setMedications, l2] = useSupabaseState("jsj-medications", { items: [], log: [] });
  const [supplies, setSupplies, l3] = useSupabaseState("jsj-supplies", { items: [], log: [] });
  const [employees, setEmployees, l4] = useSupabaseState("jsj-employees", []);
  const [attendance, setAttendance, l5] = useSupabaseState("jsj-attendance", []);
  const [payrollRuns, setPayrollRuns, l6] = useSupabaseState("jsj-payroll-runs", []);
  const [clinicSettings] = useSupabaseState("jsj-settings", {
    name: "JSJ Skin Care Medical and Aesthetic Clinic",
    address: "590 Sumulong St, Morong, Rizal",
  });

  const [active, setActive] = useState("dashboard");
  const [mobileOpen, setMobileOpen] = useState(false);
  const [toast, setToast] = useState(null);
  const toastTimer = useRef(null);
  const [confirmState, setConfirmState] = useState(null);

  const loaded = l1 && l2 && l3 && l4 && l5 && l6;

  const notify = (message, type = "success") => {
    setToast({ message, type });
    if (toastTimer.current) clearTimeout(toastTimer.current);
    toastTimer.current = setTimeout(() => setToast(null), 2800);
  };
  const askConfirm = (message, onConfirm) => setConfirmState({ message, onConfirm });

  const addTransaction = (txn) => {
    setTransactions((prev) => [{ id: uid(), createdAt: Date.now(), ...txn }, ...prev]);
  };

  if (!loaded) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-stone-50">
        <div className="flex flex-col items-center gap-3">
          <div className="w-12 h-12 rounded-full border-4 border-stone-200 border-t-rose-400 animate-spin" />
          <span className="text-sm text-stone-500">Loading clinic data\u2026</span>
        </div>
      </div>
    );
  }

  const titles = {
    dashboard: ["Dashboard", "Today's snapshot of your clinic"],
    sales: ["Sales", "Track cash in and cash out"],
    medications: ["Medications Inventory", "Stock levels and movement"],
    supplies: ["Supplies Inventory", "Stock levels and movement"],
    attendance: ["Attendance", "Employee records and time logs"],
    payroll: ["Payroll", "Compute and record employee salaries"],
  };

  return (
    <div className="min-h-screen bg-stone-50 flex" style={{ fontFamily: "'Plus Jakarta Sans', sans-serif" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Fraunces:opsz,wght@9..144,400;9..144,500;9..144,600&family=Plus+Jakarta+Sans:wght@400;500;600;700&display=swap');
        .font-serif { font-family: 'Fraunces', serif; }
        ::-webkit-scrollbar { width: 8px; height: 8px; }
        ::-webkit-scrollbar-thumb { background: #e7e5e4; border-radius: 4px; }
        @media print {
          body * { visibility: hidden; }
        }
        /* Brand palette sampled directly from the JSJ Skin Care logo:
           navy #323850 (the two "J" strokes) and gray #545454 (the "S"). */
        .bg-stone-900 { background-color: #323850 !important; }
        .text-stone-900 { color: #323850 !important; }
        .bg-rose-500 { background-color: #545454 !important; }
        .hover\:bg-rose-600:hover { background-color: #3f3f3f !important; }
        .bg-rose-50 { background-color: #ececee !important; }
        .text-rose-700 { color: #323850 !important; }
        .text-rose-600 { color: #545454 !important; }
        .text-rose-500 { color: #545454 !important; }
        .text-rose-200\/70 { color: #b9bcc6 !important; }
        .border-t-rose-400 { border-top-color: #323850 !important; }
        .focus\:ring-rose-400:focus { --tw-ring-color: #323850 !important; }
      `}</style>

      <Sidebar active={active} setActive={setActive} mobileOpen={mobileOpen} setMobileOpen={setMobileOpen} clinicName={clinicSettings.name} userEmail={session?.user?.email} onSignOut={() => supabase.auth.signOut()} />

      <main className="flex-1 min-w-0 px-4 sm:px-6 lg:px-8 py-6 lg:py-8">
        <Topbar title={titles[active][0]} subtitle={titles[active][1]} onMenu={() => setMobileOpen(true)} />

        {active === "dashboard" && (
          <Dashboard transactions={transactions} medications={medications} supplies={supplies} employees={employees} attendance={attendance} setActive={setActive} />
        )}
        {active === "sales" && (
          <SalesSection transactions={transactions} setTransactions={setTransactions} notify={notify} askConfirm={askConfirm} />
        )}
        {active === "medications" && (
          <InventoryModule
            title="Medication"
            icon={Pill}
            data={medications}
            setData={setMedications}
            cashOutCategory="Inventory"
            cashInCategory="Medications"
            allowSaleIncome={true}
            reasonsOut={MED_OUT_REASONS}
            unitOptions={["pcs", "box", "bottle", "vial", "ampule", "tube", "pack"]}
            addTransaction={addTransaction}
            notify={notify}
            askConfirm={askConfirm}
          />
        )}
        {active === "supplies" && (
          <InventoryModule
            title="Supply"
            icon={Package}
            data={supplies}
            setData={setSupplies}
            cashOutCategory="Supplies"
            allowSaleIncome={false}
            reasonsOut={SUP_OUT_REASONS}
            unitOptions={["pcs", "box", "pack", "roll", "bottle", "pair"]}
            addTransaction={addTransaction}
            notify={notify}
            askConfirm={askConfirm}
          />
        )}
        {active === "attendance" && (
          <AttendanceSection employees={employees} setEmployees={setEmployees} attendance={attendance} setAttendance={setAttendance} notify={notify} askConfirm={askConfirm} />
        )}
        {active === "payroll" && (
          <PayrollSection employees={employees} attendance={attendance} addTransaction={addTransaction} payrollRuns={payrollRuns} setPayrollRuns={setPayrollRuns} notify={notify} />
        )}
      </main>

      {confirmState && (
        <Modal
          title="Please confirm"
          onClose={() => setConfirmState(null)}
          footer={
            <>
              <button onClick={() => setConfirmState(null)} className={btnGhost}>Cancel</button>
              <button onClick={() => { confirmState.onConfirm(); setConfirmState(null); }} className={btnDanger}>Confirm</button>
            </>
          }
        >
          <p className="text-sm text-stone-600">{confirmState.message}</p>
        </Modal>
      )}
      <Toast toast={toast} />
    </div>
  );
}

/* ============================== Auth ============================== */

function LoginScreen() {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");
  const [busy, setBusy] = useState(false);

  const submit = async (e) => {
    e.preventDefault();
    setError("");
    setBusy(true);
    const { error } = await supabase.auth.signInWithPassword({ email, password });
    setBusy(false);
    if (error) setError(error.message);
  };

  return (
    <div className="min-h-screen bg-stone-50 flex items-center justify-center p-4">
      <div className="w-full max-w-sm bg-white rounded-2xl border border-stone-200 shadow-sm p-8">
        <div className="flex flex-col items-center mb-6">
          <img src={CLINIC_LOGO_FULL} alt="JSJ Skin Care" className="h-16 w-16 object-contain mb-3" />
          <h1 className="font-serif text-xl text-stone-900 text-center">JSJ Skin Care</h1>
          <p className="text-sm text-stone-500 text-center mt-1">Sign in to Clinic Operations</p>
        </div>
        <form onSubmit={submit} className="space-y-3">
          <Field label="Email">
            <input
              type="email" required value={email} onChange={(e) => setEmail(e.target.value)}
              className={inputCls()} placeholder="you@jsjskincare.com" autoFocus
            />
          </Field>
          <Field label="Password">
            <input
              type="password" required value={password} onChange={(e) => setPassword(e.target.value)}
              className={inputCls()} placeholder="\u2022\u2022\u2022\u2022\u2022\u2022\u2022\u2022"
            />
          </Field>
          {error && <p className="text-sm text-red-600">{error}</p>}
          <button type="submit" disabled={busy} className={btnPrimary + " w-full justify-center"}>
            {busy ? "Signing in\u2026" : "Sign In"}
          </button>
        </form>
        <p className="text-xs text-stone-400 text-center mt-5">
          Don't have an account yet? Ask the clinic owner to create one for you in the Supabase dashboard.
        </p>
      </div>
    </div>
  );
}

function LoadingScreen() {
  return (
    <div className="min-h-screen flex items-center justify-center bg-stone-50">
      <div className="flex flex-col items-center gap-3">
        <div className="w-12 h-12 rounded-full border-4 border-stone-200 border-t-rose-400 animate-spin" />
        <span className="text-sm text-stone-500">Loading\u2026</span>
      </div>
    </div>
  );
}

export default function App() {
  const [session, setSession] = useState(undefined); // undefined = checking, null = signed out

  useEffect(() => {
    supabase.auth.getSession().then(({ data }) => setSession(data.session));
    const { data: listener } = supabase.auth.onAuthStateChange((_event, newSession) => {
      setSession(newSession);
    });
    return () => listener.subscription.unsubscribe();
  }, []);

  if (session === undefined) return <LoadingScreen />;
  if (!session) return <LoginScreen />;
  return <ClinicApp session={session} />;
}
